// Scrabble letter values
const SCRABBLE_VALUES = {
    'A':1,'B':3,'C':3,'D':2,'E':1,'F':4,'G':2,'H':4,'I':1,'J':8,'K':5,'L':1,'M':3,
    'N':1,'O':1,'P':3,'Q':10,'R':1,'S':1,'T':1,'U':1,'V':4,'W':4,'X':8,'Y':4,'Z':10
};

// Calculate Scrabble score for a word
function getScrabbleScore(word) {
    return word.toUpperCase().split('').reduce((sum, ch) => sum + (SCRABBLE_VALUES[ch] || 0), 0);
}

// Count vowels in a word
function countVowels(word) {
    return word.toLowerCase().split('').filter(ch => 'aeiou'.includes(ch)).length;
}

